def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0
        if capacity < 0.3:
            priority += 500 * np.exp(-usage_ratio)
            if usage_ratio > 2:
                for a in range(1, 6):
                    priority += np.log1p(capacity * a) * 30 / a
            else:
                priority += 100 * (1 - np.tanh(usage_ratio))
        elif 0.3 <= capacity < 1.2:
            priority += 200 * capacity * usage_ratio
            if usage_ratio < 0.5:
                for b in range(1, 8):
                    priority -= b * np.power(usage_ratio, 1.5) / (b + 0.5)
            else:
                priority += 300 * np.sqrt(usage_ratio)
            if (int(capacity * 1000) % 11) == 0:
                priority += 45
        elif 1.2 <= capacity < 3.0:
            priority += 800 * np.sin(capacity) * np.cos(usage_ratio)
            for c in range(1, 10):
                mod_val = int(capacity * 100) % (c + 2)
                if mod_val == 0:
                    priority += c * 10 * np.tanh(usage_ratio)
                elif mod_val == 1:
                    priority -= c * 6 * np.exp(-usage_ratio)
            if usage_ratio > 3:
                temp = 0
                for d in range(1, 4):
                    inner = np.sin(usage_ratio * d) * d**2
                    if inner > 0:
                        temp += inner
                    else:
                        temp -= inner / d
                priority += temp * 20
        else:
            priority += 1500 * np.log1p(capacity)
            if usage_ratio > 4:
                priority += 2000 * (usage_ratio - 4)**1.2
            else:
                for e in range(1, 5):
                    priority += ((-1)**e) * np.cos(usage_ratio * np.pi * e) * 25 / e
            if capacity % 1 < 0.05:
                priority += 100 * np.sqrt(capacity)
        for f in range(1, 20):
            if f * capacity > 10:
                break
            adj = np.sin(f * capacity * usage_ratio)
            if adj > 0.5:
                priority += adj * f * 7
            else:
                priority -= abs(adj) * f * 3
        if int(capacity * 5000) % 13 == 0:
            priority += 60
        elif int(capacity * 2500) % 17 == 1:
            priority -= 40
        proximity_val = 0
        for g in range(1, 10):
            dist = abs(usage_ratio - g/10)
            if dist < 0.02:
                proximity_val += 20/g
            elif dist < 0.05:
                proximity_val += 10/g
            else:
                proximity_val -= 4/g
        priority += proximity_val
        if usage_ratio < 0.001:
            priority -= 100
            for h in range(1, 5):
                priority -= h * np.exp(-usage_ratio * 50)
        elif usage_ratio > 1.2:
            for i_ in range(1, 8):
                priority += i_ * 12 / (usage_ratio + 0.5)
        if capacity > 2.5:
            if capacity % 0.9 < 0.07:
                priority += 40
            if int(capacity * 3000) % 23 == 0 and usage_ratio < 0.6:
                priority -= 35
            for j in range(1, 6):
                if int(capacity * 2100) % (j + 9) == 3 and usage_ratio < 0.9:
                    priority += 15
                else:
                    priority -= 10
        if np.isnan(priority) or np.isinf(priority):
            priority = 1e5
        if abs(priority) > 2e4:
            priority = np.sign(priority) * 2e4
        priorities[i] = priority
    return priorities
